import{_ as i,o as l,c as e,a3 as r}from"./chunks/framework.BveOjhN0.js";const g=JSON.parse('{"title":"功能清单","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/basic-app/features.md","filePath":"cosmos/basic-app/features.md","lastUpdated":1783300196000}'),o={name:"cosmos/basic-app/features.md"};function t(s,a,n,c,d,h){return l(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="功能清单" tabindex="-1">功能清单 <a class="header-anchor" href="#功能清单" aria-label="Permalink to &quot;功能清单&quot;">​</a></h1><p>XiHan.BasicApp 内置了中后台系统所需的完整能力。以下按领域列出。</p><h2 id="身份与认证" tabindex="-1">身份与认证 <a class="header-anchor" href="#身份与认证" aria-label="Permalink to &quot;身份与认证&quot;">​</a></h2><ul><li>用户、角色、部门、菜单管理</li><li><strong>JWT 双令牌</strong>（Access + Refresh），多端登录与会话管理</li><li>多种登录方式：账号密码、邮箱 / 短信验证码、OAuth2（GitHub / Google / QQ）、2FA（TOTP / 邮箱 / 短信）</li><li>密码 PBKDF2 哈希；一次性验证码消费即销毁、恒定时间比较</li></ul><h2 id="权限-rbac-abac" tabindex="-1">权限（RBAC + ABAC） <a class="header-anchor" href="#权限-rbac-abac" aria-label="Permalink to &quot;权限（RBAC + ABAC）&quot;">​</a></h2><ul><li>权限码 <code>module:resource:action</code>（如 <code>saas:user:read</code>），超级管理员用字面通配 <code>*</code></li><li>角色层级继承（闭包表）、数据范围（本人 / 部门 / 租户，独立于权限码的维度）、字段级脱敏</li><li>ABAC 约束规则（时间窗 / IP / 表达式）、会话角色激活（动态职责分离）</li><li>权限申请审批与变更留痕</li></ul><blockquote><p>权限模型的完整说明见 <a href="./permissions">权限模型</a>。</p></blockquote><h2 id="多租户" tabindex="-1">多租户 <a class="header-anchor" href="#多租户" aria-label="Permalink to &quot;多租户&quot;">​</a></h2><ul><li>字段级隔离，全局数据使用 <code>TenantId=0</code> 约定</li><li>邮箱全局唯一登录，登录后按归属自动落点（控制台 / 工作台 / 租户选择），可随时切换租户</li><li>超级管理员平台态运维，可切入任意租户代为管理</li><li>租户版本（Edition）权限白名单运行时门控；开通一站式建管理员、角色与授权；降级自动回收越权授权</li></ul><h2 id="审计日志" tabindex="-1">审计日志 <a class="header-anchor" href="#审计日志" aria-label="Permalink to &quot;审计日志&quot;">​</a></h2><ul><li><strong>访问 / API / 操作 / 异常 / 登录 / 实体变更</strong> 六类日志，各自独立写入</li><li>落库前自动脱敏（密码、令牌、密钥、证件号等）；实体变更区分新增 / 修改 / 删除 / 恢复</li></ul><h2 id="代码生成" tabindex="-1">代码生成 <a class="header-anchor" href="#代码生成" aria-label="Permalink to &quot;代码生成&quot;">​</a></h2><ul><li>单表 / 树形 / 主从三种模式，从实体、DTO、API 到前端页面一键生成</li><li>基于 Scriban 模板，支持自定义；Zip 下载或直接写入文件</li></ul><h2 id="平台能力" tabindex="-1">平台能力 <a class="header-anchor" href="#平台能力" aria-label="Permalink to &quot;平台能力&quot;">​</a></h2><ul><li><strong>动态 API</strong>：应用服务经 <code>[DynamicApi]</code> 暴露，无 Controller 样板，Scalar 文档自动生成</li><li><strong>菜单单一事实源</strong>：后端 <code>PageRegistry</code> 统一注册菜单、路由、组件路径、权限码与国际化键</li><li><strong>全链路分布式缓存</strong>（授权快照、版本门控、菜单、配置、字典），写路径精准失效</li><li><strong>网关灰度发布</strong>（百分比 / 白名单 / 租户 / 请求头）、请求追踪、限流熔断</li><li><strong>消息模板</strong>（邮件 / 短信 / 站内通知，Scriban 渲染，租户可覆盖默认）、SignalR 实时通知与在线聊天</li><li><strong>文件多存储</strong>（本地 / S3 / OSS / COS / MinIO）、定时任务、审核工作流、国际化（中 / 英）</li></ul><h2 id="前端体验" tabindex="-1">前端体验 <a class="header-anchor" href="#前端体验" aria-label="Permalink to &quot;前端体验&quot;">​</a></h2><ul><li><strong>Schema 驱动列表页</strong>：搜索 / 表格 / 导出由配置生成，内置列设置、密度切换、高级搜索、个人视图保存、行悬停速览、树形模式与列宽拖拽</li><li><strong>权限 / 租户 / 偏好感知</strong>：页面、字段、操作三级按权限码过滤，字段级脱敏；列设置与搜索偏好同步到后端，多端一致</li><li>灵动岛全局反馈、多标签页、收藏夹、命令面板式全局搜索</li><li><strong>消息中心</strong>：顶部横幅、登录弹窗、通知中心，支持强制阅读与按角色 / 部门定向</li><li><strong>偏好中心</strong>：亮 / 暗主题、主题色、布局风格与紧凑度，偏好云端同步</li><li>富文本（Tiptap）与 Markdown 编辑器、Cron 可视化、JSON 编辑 / 查看</li><li>锁屏、水印、时区切换、导入 / 导出中心（模板导入、异步导出任务）</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./permissions">权限模型</a>：RBAC + ABAC 深入</li><li><a href="./architecture">系统架构</a>：模块划分与数据流</li><li><a href="./getting-started">快速开始</a>：本地跑起来</li></ul>',19)])])}const b=i(o,[["render",t]]);export{g as __pageData,b as default};
